const root = $json.body ?? $json;
const data = root.data ?? root;
const key = data.key ?? {};
const message = data.message ?? {};

const fromMe =
  key.fromMe === true ||
  data.fromMe === true ||
  root.fromMe === true;

const remoteJid =
  key.remoteJid ||
  data.remoteJid ||
  data.remote_jid ||
  root.remoteJid ||
  root.remote_jid ||
  data.from ||
  root.from ||
  "";

const text =
  message.conversation ||
  message.extendedTextMessage?.text ||
  message.imageMessage?.caption ||
  data.text ||
  root.text ||
  "";

const messageType =
  data.messageType ||
  data.type ||
  root.messageType ||
  root.type ||
  "";

const ignoredReasons = [];

if (fromMe) ignoredReasons.push("fromMe_outgoing_message");
if (!remoteJid) ignoredReasons.push("missing_remote_jid");
if (String(remoteJid).includes("status@broadcast")) ignoredReasons.push("status_broadcast");
if (String(remoteJid).endsWith("@g.us")) ignoredReasons.push("group_message_ignored");
if (!String(text).trim()) ignoredReasons.push("empty_text");

if (ignoredReasons.length > 0) {
  return [];
}

return [
  {
    json: {
      ...$json,
      _guard: {
        passed: true,
        remoteJid,
        messageType,
        textPreview: String(text).slice(0, 40),
      },
    },
  },
];

const root = $json.body ?? $json;
const data = root.data ?? root;
const key = data.key ?? {};
if (key.fromMe === true || data.fromMe === true || root.fromMe === true) {
  return [];
}
const message = data.message || {};
const remoteJid = String(key.remoteJid || "");
const sendNumber = remoteJid
  .replace(/@s\.whatsapp\.net$/i, "")
  .replace(/@c\.us$/i, "")
  .replace(/@g\.us$/i, "")
  .replace(/\D/g, "");
return [{
  json: {
    conversation_id: remoteJid,
    customer_id: remoteJid,
    provider_message_id: key.id,
    text: message.conversation ?? message.extendedTextMessage?.text ?? "",
    message_type: "text",
    channel: "whatsapp_evolution",
    language: "ar-EG",
    tone: "neutral",
    store_id: "youlya",
    remote_jid: remoteJid,
    send_number: sendNumber,
    instance_name: $node["Webhook"].json.body?.instance || $node["Webhook"].json.instance || "YoulyaMain"
  }
}];

// PLACEHOLDER: Replace with actual n8n AI Agent node (OpenAI Chat Model)
// This node receives the app response and haidi_context, then calls the LLM
// with the Haidi system prompt to generate a beautiful human reply.

// Input: $json from Call Turn Endpoint
// Expected output: { final_reply: string, intent_label: string, tone: string, used_upsell: boolean, ... }

// For now, pass through the app reply unchanged (safe fallback)
const appReply = $json.reply || "";
const appAction = $json.action || "ai_reply";
const haidiContext = $json.haidi_context || {};

return [{
  json: {
    final_reply: appReply,
    intent_label: "fallback",
    tone: "friendly",
    used_upsell: false,
    recommended_next_step: "",
    safety_notes: ["placeholder_mode: app_reply_passed_through"],
    _app_action: appAction,
    _haidi_context_present: Boolean($json.haidi_context),
  },
}];

const appReply = $node["Call Turn Endpoint"].json.reply || "";
const appAction = $node["Call Turn Endpoint"].json.action || "ai_reply";
const haidiRaw = $json.final_reply ? $json : null;

if (!haidiRaw || typeof haidiRaw.final_reply !== "string" || !haidiRaw.final_reply.trim()) {
  return [{
    json: {
      reply: appReply,
      action: appAction,
      haidi_valid: false,
      haidi_fallback: true,
      number: $node["Normalize Message"].json.send_number,
    },
  }];
}

const unsafePhrases = ["تم تأكيد الأوردر", "الأوردر اتعمل", "الأوردر اتأكد", "تم إنشاء الأوردر"];
const hasUnsafeOrderClaim = unsafePhrases.some((p) => haidiRaw.final_reply.includes(p));
if (hasUnsafeOrderClaim && appAction !== "order_created") {
  return [{
    json: {
      reply: appReply,
      action: appAction,
      haidi_valid: false,
      haidi_fallback: true,
      haidi_blocked_reason: "unsafe_order_claim",
      number: $node["Normalize Message"].json.send_number,
    },
  }];
}

return [{
  json: {
    reply: haidiRaw.final_reply,
    action: appAction,
    haidi_valid: true,
    haidi_output: haidiRaw,
    number: $node["Normalize Message"].json.send_number,
  },
}];

const action = $json.action || "error";

const reply =
  $json.reply ||
  $json.message ||
  "حصل خطأ تقني بسيط، ممكن تبعتي الرسالة تاني؟";

const normalized = $node["Normalize Message"].json;
const fallbackNumber = String(normalized.send_number || normalized.remote_jid || normalized.conversation_id || "")
  .replace(/@s\.whatsapp\.net$/i, "")
  .replace(/@c\.us$/i, "")
  .replace(/@g\.us$/i, "")
  .replace(/\D/g, "");

const number = $json.number || normalized.send_number || fallbackNumber;
const shouldSend = action !== "duplicate_ignored" && Boolean(reply) && Boolean(number);

return [
  {
    json: {
      ...$json,
      action,
      reply,
      shouldSend,
      number,
    },
  },
];
